#include <vector>
#include <algorithm>
#include <unordered_set>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    if (edges.empty()) {
        return 0;
    }
    sort(edges.begin(), edges.end(), [](const auto& a, const auto& b) { return a[2] < b[2]; });
    long long low = 0, high = edges.back()[2];
    long long answer = high;

    auto countComponents = [&](long long X) {
        vector<long long> parent(n);
        vector<long long> rank(n, 1);
        for (long long i = 0; i < n; ++i) {
            parent[i] = i;
        }

        auto find = [&](long long u) {
            if (parent[u] != u) {
                parent[u] = find(parent[u]);
            }
            return parent[u];
        };

        auto union_op = [&](long long u, long long v) {
            long long rootU = find(u);
            long long rootV = find(v);
            if (rootU != rootV) {
                if (rank[rootU] < rank[rootV]) {
                    parent[rootU] = rootV;
                } else {
                    parent[rootV] = rootU;
                    if (rank[rootU] == rank[rootV]) {
                        rank[rootU]++;
                    }
                }
            }
        };

        for (const auto& edge : edges) {
            if (edge[2] <= X) {
                union_op(edge[0], edge[1]);
            }
        }

        unordered_set<long long> roots;
        for (long long i = 0; i < n; ++i) {
            roots.insert(find(i));
        }
        return roots.size();
    };

    while (low <= high) {
        long long mid = (low + high) / 2;
        long long components = countComponents(mid);
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
