        for (let [u, v, w] of edges) {
            if (w <= X) {
                union(u, v);
            }
        }

        let roots = new Set();
        for (let i = 0; i < n; i++) {
            roots.add(find(i));
        }
        return roots.size;
    }

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let components = countComponents(mid);
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
